graphics AS _pd WHERE _pd.patient_id = HypoglycemicMed.patient_id LIMIT 1), 'birthDate') AS VARCHAR), fhirpath_text(HypoglycemicMed.resource, 'effective')) AS VARCHAR), '{"value": 1.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, FALSE) WHEN starts_with(LTRIM(fhirpath_text(HypoglycemicMed.resource, 'effective')), '{') AND (json_extract_string(fhirpath_text(HypoglycemicMed.resource, 'effective'), '$.low') IS NOT NULL OR json_extract_string(fhirpath_text(HypoglycemicMed.resource, 'effective'), '$.high') IS NOT NULL) THEN intervalFromBounds(CAST(dateAddQuantity(CAST(fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = HypoglycemicMed.patient_id LIMIT 1), 'birthDate') AS VARCHAR), fhirpath_text(HypoglycemicMed.resource, 'effective.low')) AS VARCHAR), CAST(dateAddQuantity(CAST(dateAddQuantity(CAST(fhirpath_text((SELECT _pd.resource FROM _patient_demographics AS _pd WHERE _pd.patient_id = HypoglycemicMed.patient_id LIMIT 1), 'birthDate') AS VARCHAR), fhirpath_text(HypoglycemicMed.resource, 'effective.high')) AS VARCHAR), '{"value": 1.0, "unit": "year", "system": "http://unitsofmeasure.org"}') AS VARCHAR), TRUE, FALSE) WHEN starts_with(LTRIM(fhirpath_text(HypoglycemicMed.resource, 'effective')), '{') AND (json_extract_string(fhirpath_text(HypoglycemicMed.resource, 'effective'), '$.event') IS NOT NULL OR json_extract_string(fhirpath_text(HypoglycemicMed.resource, 'effective'), '$.repeat') IS NOT NULL) THEN CQLMessage(NULL, TRUE, 'NOT_IMPLEMENTED', 'Error', 'Calculation of an interval from a Timing value is not supported') ELSE NULL END) AND HypoglycemicMed.patient_id = Hospitalization.patient_id
