ds(fhirpath_text(GlucoseTest.resource, 'effective'), fhirpath_text(GlucoseTest.resource, 'effective'), TRUE, TRUE) END) ELSE intervalEnd(CASE WHEN fhirpath_text(GlucoseTest.resource, 'effective') IS NULL THEN NULL WHEN starts_with(LTRIM(fhirpath_text(GlucoseTest.resource, 'effective')), '{') THEN fhirpath_text(GlucoseTest.resource, 'effective') ELSE intervalFromBounds(fhirpath_text(GlucoseTest.resource, 'effective'), fhirpath_text(GlucoseTest.resource, 'effective'), TRUE, TRUE) END) END AS VARCHAR)) AND GlucoseTest.patient_id = InpatientHospitalDays.patient_id))) FROM (SELECT unnest(from_json(json_extract_string(InpatientHospitalDays.resource, '$.relevantDays'), '["VARCHAR"]')) AS _lt_EncounterDay) AS _lt_unnest)) AS _resource_data FROM "Days in Hospitalization" AS InpatientHospitalDays) AS _inner
),
"Days with Hyperglycemic Events" AS (
SELECT _inner.patient_id, _inner._resource_data AS resource FROM (SELECT patient_id, json_object('encounter', json_extract_string(EncounterWithResultDays.resource, '$.encounter'), 'relevantPeriod', json_extract_string(EncounterWithResultDays.resource, '$.relevantPeriod'), 'eligibleEventDays', (SELECT COALESCE('[' || string_agg(json_object('dayIndex', fhirpath_text(_lt_EncounterDay, 'dayNumber'), 'dayPeriod', fhirpath_text(_lt_EncounterDay, 'dayPeriod'), 'hasHyperglycemicEvent', fhirpath_bool(_lt_EncounterDay, 'hasSevereResult') OR fhirpath_bool(_lt_EncounterDay, 'hasNoGlucoseTest') AND fhirpath_bool(LIST_EXTRACT(from_json(json_extract_string(EncounterWithResultDays.resource, '$.relevantDays'), '["VARCHAR"]'), CAST(TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text(_lt_EncounterDay, 'dayNumber')), '{') THEN json_extract_string(fhirpath_text(_lt_EncounterDay, 'dayNumber'), '$.value') ELSE fhirpath_text(_lt_EncounterDay, 'dayNumber') END AS DOUBLE) - 2 + 1 AS BIGINT)), 'hasElevatedResult') AND fhirpath_bool(LIST_EXTRACT(from_json(json_extract_string(EncounterWithResultDays.resource, '$.relevantDays'), '["VARCHAR"]'), CAST(TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text(_lt_EncounterDay, 'dayNumber')), '{') THEN json_extract_string(fhirpath_text(_lt_EncounterDay, 'dayNumber'), '$.value') ELSE fhirpath_text(_lt_EncounterDay, 'dayNumber') END AS DOUBLE) - 3 + 1 AS BIGINT)), 'hasElevatedResult')), ',') || ']', '[]') FROM (SELECT unnest(from_json(json_extract_string(EncounterWithResultDays.resource, '$.relevantDays'), '["VARCHAR"]')) AS _lt_EncounterDay) AS _lt_unnest WHERE TRY_CAST(CASE WHEN starts_with(LTRIM(fhirpath_text(_lt_EncounterDay, 'dayNumber')), '{') THEN json_extract_string(fhirpath_text(_lt_EncounterDay, 'dayNumber'), '$.value') ELSE fhirpath_text(_lt_EncounterDay, 'dayNumber') END AS DOUBLE) > 1)) AS _resource_data FROM "Days with Glucose Results" AS EncounterWithResultDays) AS _inner
),
"Encounter with Hyperglycemic Events" AS (
SELECT HyperglycemicEventDays.patient_id, json_extract_string(HyperglycemicEventDays.resource, '$.encounter') AS value FROM "Days with Hyperglycemic Events" AS HyperglycemicEventDays WHERE EXISTS (SELECT 1 FROM (SELECT unnest(from_json(json_extract_string(HyperglycemicEventDays.resource, '$.eligibleEventDays'), '["VARCHAR"]')) AS _lt_EligibleEventDay) AS _lt_unnest WHERE fhirpath_bool(_lt_EligibleEventDay, 'hasHyperglycemicEvent'))
),
"Numerator" AS (
SELECT * FROM "Encounter with Hyperglycemic Events"
),
"Numerator Exclusions" AS (
SELECT * FROM "Encounter with Early Glucose Greater Than 600 or with Comfort or Hospice Care"
),
"SDE Ethnicity" AS (
SELECT * FROM "SDE.SDE Ethnicity"
),
"SDE Payer" AS (
SELECT * FROM "SDE.SDE Payer"
),
"SDE Race" AS (
SELECT * FROM "SDE.SDE Race"
),
"SDE Sex" AS (
SELECT * FROM "SDE.SDE Sex"
)
SELECT p.patient_id, (SELECT COALESCE(LIST(json_extract_string("Initial Population".resource, '$.resourceType') || '/' || json_extract_string("Initial Population".resource, '$.id')), []) FROM "Initial Population" WHERE "Initial Population".patient_id = p.patient_id AND "Initial Population".resource IS NOT NULL) AS "Initial Population", (SELECT COALESCE(LIST(json_extract_string("Denominator".resource, '$.resourceType') || '/' || json_extract_string("Denominator".resource, '$.id')), []) FROM "Denominator" WHERE "Denominator".patient_id = p.patient_id AND "Denominator".resource IS NOT NULL) AS Denominator, (SELECT COALESCE(LIST(json_extract_string("Denominator Exclusions".resource, '$.resourceType') || '/' || json_extract_string("Denominator Exclusions".resource, '$.id')), []) FROM "Denominator Exclusions" WHERE "Denominator Exclusions".patient_id = p.patient_id AND "Denominator Exclusions".resource IS NOT NULL) AS "Denominator Exclusions", (SELECT COALESCE(LIST("Numerator".value), []) FROM "Numerator" WHERE "Numerator".patient_id = p.patient_id) AS Numerator, (SELECT COALESCE(LIST(json_extract_string("Numerator Exclusions".resource, '$.resourceType') || '/' || json_extract_string("Numerator Exclusions".resource, '$.id')), []) FROM "Numerator Exclusions" WHERE "Numerator Exclusions".patient_id = p.patient_id AND "Numerator Exclusions".resource IS NOT NULL) AS "Numerator Exclusions" FROM _patients p ORDER BY p.patient_id ASC
